import{_ as e,o as a,c as d,ag as r}from"./chunks/framework.f_9xDHrT.js";const b=JSON.parse('{"title":"宇宙探索","description":"MissFisher 的宇宙探索任务说明。","frontmatter":{"title":"宇宙探索","description":"MissFisher 的宇宙探索任务说明。"},"headers":[],"relativePath":"manual/scenarios/cosmic.md","filePath":"manual/scenarios/cosmic.md","lastUpdated":1777745397000}'),s={name:"manual/scenarios/cosmic.md"};function i(l,t,n,o,c,h){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="宇宙探索" tabindex="-1">宇宙探索 <a class="header-anchor" href="#宇宙探索" aria-label="Permalink to &quot;宇宙探索&quot;">​</a></h1><ul><li><strong>相关设置项：</strong><br> 捕鱼人时自动提交任务<br> ICE 适配模式<br> 禁用银星提交</li></ul><h2 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to &quot;启动&quot;">​</a></h2><p>在已勾选 ICE 适配模式时，使用捕鱼人接取宇宙探索任务后，MissFisher 会自动识别任务并启动对应预设。</p><p>也可以手动切换到宇宙模式并启动，将自动识别当前任务并调用预设。</p><h2 id="紫色稀有度工具进度" tabindex="-1">紫色稀有度工具进度 <a class="header-anchor" href="#紫色稀有度工具进度" aria-label="Permalink to &quot;紫色稀有度工具进度&quot;">​</a></h2><p>可先从憧憬湾的探索任务开始，直到中级阶段（中级I-1）再前往法恩娜行星；<br> 在高级阶段（高级A-1）时，前往俄匊斯行星。</p><table tabindex="0"><thead><tr><th style="text-align:center;">星球</th><th>类别</th><th>探索任务名</th><th>说明</th></tr></thead><tbody><tr><td style="text-align:center;">憧憬湾</td><td>C 类</td><td>协助调查基地西北侧的水质</td><td>可以高效获取数据 I、数据 II</td></tr><tr><td style="text-align:center;">憧憬湾</td><td>A 类</td><td>检验钓场的多样性</td><td>可以高效获取数据 III、数据 IV</td></tr><tr><td style="text-align:center;">法恩娜</td><td>C 类</td><td>高效筹备水产食品</td><td>可以高效获取数据 I、数据 II、数据 III</td></tr><tr><td style="text-align:center;">法恩娜</td><td>A 类</td><td>支援利用水产资源开发精密镜片</td><td>可以高效获取数据 III、数据 IV、数据 V</td></tr><tr><td style="text-align:center;">法恩娜</td><td>A 类</td><td>【高难】大型水产资源的捕获调查</td><td>可以高效获取数据 II、数据 IV、数据 V</td></tr><tr><td style="text-align:center;">俄匊斯</td><td>B 类</td><td>调查养殖鱼的重力异常适应性</td><td>可以高效获取数据 II、数据 III、数据 IV</td></tr><tr><td style="text-align:center;">俄匊斯</td><td>A 类</td><td>调查海洋水产品的可食用性</td><td>可以高效获取数据 I、数据 V、数据 VI</td></tr></tbody></table><h2 id="捕鱼人实绩" tabindex="-1">捕鱼人实绩 <a class="header-anchor" href="#捕鱼人实绩" aria-label="Permalink to &quot;捕鱼人实绩&quot;">​</a></h2><blockquote><p>技巧点</p></blockquote><p>也可尝试紧急、时间限定与天气限定任务，通常而言它们易于完成，且会给予大量信用点 / 技巧点。</p><table tabindex="0"><thead><tr><th style="text-align:center;">探索地点</th><th>类别</th><th>探索任务名</th><th>说明</th></tr></thead><tbody><tr><td style="text-align:center;">憧憬湾</td><td>A 类</td><td>【高难】制作改良版月凝胶</td><td>可以高效获取捕鱼人技巧点，<br>需要你的炼金术师职业有正常的等级、<br>技能和已部分禁忌镶嵌的新装备（对于7.5），<br>且需要使用生产职业用的食品</td></tr></tbody></table><h2 id="ice的宇宙探索" tabindex="-1">ICE的宇宙探索 <a class="header-anchor" href="#ice的宇宙探索" aria-label="Permalink to &quot;ICE的宇宙探索&quot;">​</a></h2><blockquote><p>Ice&#39;s Cosmic Exploration</p></blockquote><p>这是一个可以刷取、提交宇宙探索任务的插件，有助于专门刷取并只完成特定任务。</p><ul><li>第三方仓库链接：</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://raw.githubusercontent.com/QiongHHHZZZ/DalamudPlugins/main/pluginmaster.json</span></span></code></pre></div>',17)])])}const u=e(s,[["render",i]]);export{b as __pageData,u as default};
